window.PACTO.acts["dec-2013-1313"]={"label": "DECISIONE N. 1313/2013/UE DEL PARLAMENTO EUROPEO E DEL CONSIGLIO", "short": "Dec. 1313/2013", "file": "ext-dec-2013-1313.html", "external": true, "version": "consolidato 2023-12-18", "eurlex": "https://eur-lex.europa.eu/eli/dec/2013/1313/oj/ita", "articles": {"1": {"label": "Articolo 1", "heading": "Obiettivo generale e oggetto", "anchor": "art_1", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il meccanismo unionale di protezione civile (il \"meccanismo unionale\") è destinato a rafforzare la cooperazione tra l'Unione e gli Stati membri e a facilitare il coordinamento nel settore della protezione civile al fine di migliorare l'efficacia dei sistemi di prevenzione, preparazione e risposta alle catastrofi naturali e provocate dall'uomo.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il meccanismo unionale mira a garantire in primo luogo la protezione delle persone, ma anche dell’ambiente e dei beni, compreso il patrimonio culturale, da ogni tipo di catastrofi naturali e provocate dall’uomo, tra cui le conseguenze di atti di terrorismo, le catastrofi tecnologiche, radiologiche o ambientali, l’inquinamento marino, il dissesto idrogeologico e le emergenze sanitarie gravi, che si verificano all’interno e al di fuori dell’Unione. Nel caso delle conseguenze di atti di terrorismo o di catastrofi radiologiche, il meccanismo unionale può coprire soltanto le azioni di preparazione e di risposta.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il meccanismo unionale promuove la solidarietà tra gli Stati membri attraverso la cooperazione e il coordinamento delle attività, fatta salva la responsabilità primaria degli Stati membri di proteggere dalle catastrofi le persone, l’ambiente e i beni, compreso il patrimonio culturale, sul loro territorio e di dotare i rispettivi sistemi di gestione delle catastrofi di mezzi sufficienti per prevenire e affrontare in modo adeguato e coerente catastrofi di natura e dimensioni ragionevolmente prevedibili e per le quali possono essere preparati.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La presente decisione stabilisce le norme generali per il meccanismo unionale e le norme per la concessione dell'assistenza finanziaria nell'ambito del meccanismo unionale.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Il meccanismo unionale non ha effetti sugli obblighi derivanti dai pertinenti atti giuridici dell'Unione, derivanti dal trattato che istituisce la Comunità europea dell'energia atomica o dagli accordi internazionali esistenti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">La presente decisione non si applica alle azioni condotte ai sensi del regolamento (CE) n. 1257/96, del regolamento (CE) n. 1406/2002, del regolamento (CE) n. 1717/2006, della decisione n. 1082/2013/UE del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">1</span>\n) o della normativa dell'Unione sui programmi d'azione in materia di salute, affari interni e giustizia.</div>\n</div>"]]}, "2": {"label": "Articolo 2", "heading": "Ambito d'applicazione", "anchor": "art_2", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La presente decisione si applica alla cooperazione nel settore della protezione civile. Tale cooperazione comprende:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le azioni di prevenzione e preparazione all'interno dell'Unione e, per quanto riguarda l'articolo 5, paragrafo 2, l'articolo 13, paragrafo 3, e l'articolo 28, anche al di fuori dell'Unione; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le azioni di assistenza in risposta alle conseguenze negative immediate di una catastrofe, all'interno e al di fuori dell'Unione, comprese nei paesi di cui all'articolo 28, paragrafo 1, a seguito di una richiesta di assistenza presentata mediante il meccanismo.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La presente decisione tiene conto delle esigenze specifiche delle regioni isolate, ultraperiferiche o di altre regioni o isole dell'Unione in termini di prevenzione, preparazione e risposta alle catastrofi e delle esigenze specifiche dei paesi e territori d'Oltremare nella risposta alle catastrofi.</div>\n</div>"]]}, "3": {"label": "Articolo 3", "heading": "Obiettivi specifici", "anchor": "art_3", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il meccanismo unionale sostiene, integra e facilita il coordinamento dell'azione degli Stati membri per perseguire i seguenti obiettivi specifici comuni:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">conseguire un livello elevato di protezione contro le catastrofi prevenendone o riducendone gli effetti potenziali, promuovendo una cultura di prevenzione e migliorando la cooperazione tra la protezione civile e gli altri servizi competenti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">migliorare la preparazione a livello di Stato membro e dell'Unione in risposta alle catastrofi;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M3\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">facilitare una risposta rapida ed efficace in caso di catastrofi in atto o imminenti, anche adottando misure tese a mitigarne gli effetti immediati e incoraggiando gli Stati membri ad impegnarsi per rimuovere gli ostacoli burocratici;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">rafforzare la consapevolezza e la preparazione dei cittadini nei confronti delle catastrofi;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M2\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">incrementare la disponibilità e l'utilizzo di conoscenze scientifiche relative alle catastrofi; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">intensificare le attività di cooperazione e coordinamento a livello transfrontaliero e tra Stati membri esposti allo stesso tipo di catastrofi.</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Gli indicatori sono utilizzati, secondo le necessità, per monitorare, valutare e rivedere l'applicazione della presente decisione. Tali indicatori sono i seguenti:</p>\n<p class=\"modref\">\n▼M2\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">progressi nell'attuazione del quadro di prevenzione delle catastrofi misurati in funzione del numero di Stati membri che hanno reso disponibili alla Commissione le informazioni di cui all'articolo 6, paragrafo 1, lettera d);</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M3\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">progressi nel rafforzamento del livello di preparazione alle catastrofi misurati in funzione della quantità dei mezzi di risposta compresi nel pool europeo di protezione civile in relazione agli obiettivi di capacità di cui all’articolo 11, al numero di moduli registrati nel sistema comune di comunicazione e informazione in caso di emergenza (<span class=\"italics\">Common Emergency Communication and Information System</span> — CECIS) e al numero di risorse di rescEU stabilite per fornire assistenza in situazioni particolarmente pressanti;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">progressi nel miglioramento della risposta alle catastrofi misurati in funzione della velocità degli interventi nell'ambito del meccanismo unionale e della misura in cui l'assistenza contribuisce al soddisfacimento delle esigenze sul campo; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">progressi nel rafforzamento della consapevolezza e della preparazione dei cittadini nei confronti delle catastrofi: misurati in funzione del livello di consapevolezza dei cittadini dell'Unione rispetto ai rischi nelle rispettive regioni.</p>\n</div>\n</div>\n</div>\n</div>"]]}, "4": {"label": "Articolo 4", "heading": "Definizioni", "anchor": "art_4", "frags": [[null, "<p class=\"norm\">Ai fini della presente decisione, si intende per:</p>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">1.</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">\"catastrofe\" : qualsiasi situazione che abbia o possa avere conseguenze gravi sulle persone, l'ambiente o i beni, compreso il patrimonio culturale;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">2.</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">\"risposta\" : qualsiasi azione intrapresa previa richiesta di assistenza nell'ambito del meccanismo unionale nel caso di un imminente catastrofe, oppure durante o dopo la stessa per affrontarne gli effetti negativi immediati;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">3.</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">\"preparazione\" : stato di prontezza e capacità di mezzi umani e materiali, strutture, comunità e organizzazioni ottenuto da un'attività condotta in anticipo, in virtù del quale è possibile garantire una risposta rapida ed efficace a una catastrofe;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">4.</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">\"prevenzione\" : qualsiasi azione intesa a ridurre i rischi o a mitigare gli effetti negativi di una catastrofe per le persone, l'ambiente e i beni, compreso il patrimonio culturale;</p>\n</td>\n</tr>\n</table>"], [null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">4 <span class=\"italics\">bis</span>.</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">\"obiettivi dell’Unione in materia di resilienza alle catastrofi\" : obiettivi non vincolanti stabiliti nel settore della protezione civile per sostenere azioni di prevenzione e preparazione al fine di migliorare la capacità dell’Unione e dei suoi Stati membri di resistere agli effetti di una catastrofe che provoca o è in grado di provocare effetti transfrontalieri multinazionali;</p>\n</td>\n</tr>\n</table>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">5.</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">\"allerta rapida\" : fornitura tempestiva ed efficace di informazioni che mettano in condizione di agire per evitare o ridurre i rischi e gli effetti negativi di una catastrofe e di facilitare la preparazione di una risposta efficace;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">6.</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">\"modulo\" : un insieme autosufficiente e autonomo di mezzi degli Stati membri predefinito in base ai compiti e alle necessità o una squadra mobile operativa degli Stati membri costituita da un insieme di mezzi umani e materiali, che si può descrivere in termini di capacità di intervento o di compiti che è in grado di svolgere;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">7.</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">\"valutazione del rischio\" : l'intero processo intersettoriale di individuazione, analisi e stima dei rischi a livello nazionale o al livello subnazionale appropriato;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">8.</p>\n</td>\n<td valign=\"top\">\n<p class=\"normal\">\"capacità di gestione dei rischi\" : </p>\n<p class=\"norm\">la capacità di uno Stato membro o delle sue regioni di ridurre, adeguarsi ai o mitigare i rischi (impatti e probabilità di un disastro), individuati nelle sue valutazioni dei rischi fino a livelli accettabili in detto Stato membro. La capacità di gestione dei rischi è valutata in termini di capacità tecnica, finanziaria e amministrativa di condurre adeguatamente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">valutazioni dei rischi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">pianificazione della gestione del rischio per la prevenzione e la preparazione; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">misure di prevenzione e preparazione ai rischi;</p>\n</div>\n</div>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">9.</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">\"supporto della nazione ospitante\" : qualsiasi azione intrapresa nelle fasi di preparazione e risposta dal paese che riceve o invia assistenza, o dalla Commissione, per rimuovere gli ostacoli prevedibili all'assistenza internazionale offerta nell'ambito del meccanismo unionale. Esso comprende il sostegno prestato dagli Stati membri per facilitare il transito di tale assistenza attraverso il loro territorio;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">10.</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">\"mezzo di risposta\" : l'assistenza che può essere fornita su richiesta tramite il meccanismo unionale;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">11.</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">\"supporto logistico\" : attrezzature o servizi essenziali atti a consentire alle squadre di esperti di cui all'articolo 17, paragrafo 1, di svolgere i loro compiti, in particolare con riguardo a comunicazione, alloggio temporaneo, vitto o trasporto all'interno del paese;</p>\n</td>\n</tr>\n</table>"], [null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">12.</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">\"stato partecipante\" : un paese terzo che partecipa al meccanismo unionale ai sensi dell'articolo 28, paragrafo 1.</p>\n</td>\n</tr>\n</table>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "5": {"label": "Articolo 5", "heading": "Azioni di prevenzione", "anchor": "art_5", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Per conseguire gli obiettivi e condurre le azioni di prevenzione, la Commissione:</p>\n<p class=\"modref\">\n▼M2\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">agisce per migliorare le conoscenze di base sui rischi di catastrofe nonché per facilitare e promuovere la cooperazione e la condivisione di conoscenze, risultati di ricerche e innovazioni scientifiche, così come la condivisione delle migliori prassi e informazioni, anche tra gli Stati membri che condividono rischi comuni;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sostiene e promuove l'attività di valutazione e mappatura del rischio da parte degli Stati membri attraverso la condivisione di migliori prassi, e facilita l'accesso alle conoscenze e competenze specifiche su questioni di comune interesse;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M3\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">elabora e aggiorna periodicamente una panoramica e una mappatura intersettoriali dei rischi di catastrofi naturali e provocate dall’uomo, compresi i rischi di catastrofi che provocano o sono in grado di provocare effetti transfrontalieri multinazionali, cui l’Unione può essere esposta, assumendo un approccio coerente in diversi settori d’intervento che possono riguardare o influire sulla prevenzione delle catastrofi e tenendo debitamente conto delle probabili ripercussioni dei cambiamenti climatici;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">incoraggia uno scambio di buone prassi sulla preparazione dei sistemi nazionali di protezione civile a far fronte all'impatto dei cambiamenti climatici;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">promuove e sostiene lo sviluppo e l'attuazione dell'attività di gestione dei rischi da parte degli Stati membri attraverso la condivisione di buone prassi e facilita l'accesso alle conoscenze e competenze specifiche su questioni di comune interesse;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M2\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">raccoglie e diffonde le informazioni messe a disposizione dagli Stati membri; organizza uno scambio di esperienze sulla valutazione della capacità di gestione dei rischi; e facilita la condivisione di buone prassi nella pianificazione della prevenzione e della preparazione, anche attraverso valutazioni inter pares volontarie;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M3\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">riferisce periodicamente, secondo le scadenze indicate all’articolo 6, paragrafo 1, lettera d), al Parlamento europeo e al Consiglio sui progressi compiuti nell’attuazione dell’articolo 6;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">promuove l'uso di vari fondi dell'Unione che possono sostenere la prevenzione sostenibile delle catastrofi e incoraggia gli Stati membri e le regioni a sfruttare tali possibilità di finanziamento;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M2\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">mette in luce l'importanza della prevenzione dei rischi, sostiene gli Stati membri nella sensibilizzazione dell'opinione pubblica, nonché nelle campagne pubbliche di informazione ed educazione, e sostiene gli sforzi profusi dagli Stati membri nell'informare il pubblico circa i sistemi di allerta fornendo orientamenti su tali sistemi, anche a livello transfrontaliero;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>j) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">promuove misure di prevenzione negli Stati membri e nei paesi terzi di cui all'articolo 28 attraverso la condivisione di buone prassi, e facilita l'accesso alle conoscenze e competenze specifiche su questioni di interesse comune; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>k) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">in stretta consultazione con gli Stati membri, intraprende altre necessarie azioni di prevenzione complementari e di supporto al fine di conseguire l'obiettivo di cui all'articolo 3, paragrafo 1, lettera a).</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Su richiesta di uno Stato membro, di un paese terzo o delle Nazioni Unite o relative agenzie, la Commissione può inviare sul posto una squadra di esperti al fine di fornire consulenza in merito alle misure di prevenzione.</div>\n</div>"]]}, "6": {"label": "Articolo 6", "heading": "Gestione dei rischi", "anchor": "art_6", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Per favorire un approccio coerente ed efficace in materia di prevenzione e preparazione alle catastrofi mediante la condivisione di informazioni non sensibili, vale a dire informazioni la cui divulgazione non sarebbe contraria agli interessi essenziali della sicurezza degli Stati membri, e per favorire lo scambio delle migliori prassi nell'ambito del meccanismo unionale, gli Stati membri:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">elaborano ulteriormente le valutazioni del rischio a livello nazionale o al livello subnazionale appropriato;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">elaborano ulteriormente la valutazione della capacità di gestione dei rischi a livello nazionale o al livello subnazionale appropriato;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M3\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">elaborano e perfezionano ulteriormente le rispettive pianificazioni della gestione dei rischi di catastrofe a livello nazionale o al livello subnazionale appropriato, anche per quanto riguarda la collaborazione transfrontaliera, tenendo conto degli obiettivi dell’Unione in materia di resilienza alle catastrofi di cui al paragrafo 5, se stabiliti, e dei rischi connessi a catastrofi che provocano o sono in grado di provocare effetti transfrontalieri multinazionali;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">mettono a disposizione della Commissione una sintesi degli elementi rilevanti delle valutazioni di cui alle lettere a) e b), concentrandosi sui rischi principali. Per i rischi principali che hanno conseguenze transfrontaliere e i rischi connessi a catastrofi che provocano o sono in grado di provocare effetti transfrontalieri multinazionali e, ove opportuno, per i rischi poco probabili dall’impatto elevato, gli Stati membri illustrano le misure di prevenzione e preparazione prioritarie. La sintesi viene fornita alla Commissione entro il 31 dicembre 2020 e successivamente ogni tre anni, nonché ogni volta che vi siano modifiche di rilievo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">partecipano, su base volontaria, a un esame inter pares della valutazione della capacità di gestione dei rischi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">in linea con gli impegni internazionali, migliorano la raccolta di dati sulle perdite dovute a catastrofi a livello nazionale o al livello subnazionale adeguato per garantire l’elaborazione di scenari basati su elementi concreti di cui all’articolo 10, paragrafo 1, e l’identificazione di carenze dei mezzi di risposta alle catastrofi.</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M2\n</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La Commissione, di concerto con gli Stati membri, può inoltre istituire specifici meccanismi di consultazione per migliorare opportunamente la pianificazione e il coordinamento della prevenzione e della preparazione tra gli Stati membri esposti a tipologie di catastrofi analoghe, anche in caso di rischi transfrontalieri e di rischi poco probabili dall'impatto molto elevato individuati a norma del paragrafo 1, lettera d).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La Commissione, insieme con gli Stati membri ed entro il 22 dicembre 2019, elabora inoltre ulteriormente gli orientamenti sulle modalità di presentazione della sintesi di cui al paragrafo 1, lettera d).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Qualora uno Stato membro richieda di frequente lo stesso tipo di assistenza tramite il meccanismo unionale per lo stesso tipo di catastrofe, la Commissione, in seguito ad un'attenta analisi dei motivi e delle circostanze che hanno portato all'attivazione e con l'obiettivo di aiutare lo Stato membro interessato a rafforzare il proprio livello di prevenzione e preparazione, può:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">richiedere a tale Stato membro di fornire informazioni aggiuntive sulle misure di prevenzione e preparazione specifiche relative al rischio corrispondente a quella tipologia di catastrofe; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ove opportuno, sulla base delle informazioni fornite:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">proporre la mobilitazione di una squadra di esperti sul posto per fornire consulenza in merito alle misure di prevenzione e preparazione; o</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">formulare raccomandazioni per rafforzare il livello di prevenzione e preparazione nello Stato membro interessato. La Commissione e tale Stato membro si tengono reciprocamente informati su ogni eventuale misura adottata a seguito di tali raccomandazioni.</p>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Se uno Stato membro richiede lo stesso tipo di assistenza tramite il meccanismo unionale per lo stesso tipo di catastrofe tre volte nel corso di tre anni consecutivi, si applicano le lettere a) e b), a meno che un'attenta analisi dei motivi e delle circostanze alla base di tali attivazioni frequenti non dimostri che tale misura non è necessaria.</p>"], [null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">La Commissione, in cooperazione con gli Stati membri, stabilisce e sviluppa gli obiettivi dell’Unione in materia di resilienza alle catastrofi nel settore della protezione civile e adotta raccomandazioni per definirli quale base comune non vincolante per sostenere le azioni di prevenzione e preparazione in caso di catastrofi che provocano o sono in grado di provocare effetti transfrontalieri multinazionali. Tali obiettivi si basano su scenari attuali e prospettici che includono gli impatti dei cambiamenti climatici sui rischi di catastrofi, dati relativi ad eventi passati e l’analisi dell’impatto intersettoriale, prestando particolare attenzione ai gruppi vulnerabili. Nello sviluppo degli obiettivi dell’Unione in materia di resilienza alle catastrofi, la Commissione tiene conto delle catastrofi ricorrenti che colpiscono gli Stati membri e propone agli Stati membri di adottare misure specifiche, ivi incluse eventuali misure da attuare utilizzando i fondi dell’Unione, al fine di rafforzare la resilienza a tali catastrofi.</div>\n</div>"]]}, "7": {"label": "Articolo 7", "heading": "Centro di coordinamento della risposta alle emergenze", "anchor": "art_7", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">È istituito il Centro di coordinamento della risposta alle emergenze (<span class=\"italics\">Emergency Response Coordination Centre</span> — ERCC). L’ERCC garantisce la capacità operativa 24 ore su 24 e sette giorni su sette ed è al servizio degli Stati membri e della Commissione nel perseguimento degli obiettivi del meccanismo unionale.</div>\n</div>"], [null, "<p class=\"norm\">In particolare l’ERCC coordina, monitora e coadiuva in tempo reale la risposta alle emergenze a livello dell’Unione. L’ERCC opera a stretto contatto con le autorità nazionali di protezione civile e i pertinenti organismi dell’Unione per promuovere un approccio intersettoriale alla gestione delle catastrofi.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L’ERCC dispone di capacità operative, analitiche, di monitoraggio, di gestione delle informazioni e di comunicazione per affrontare un’ampia gamma di emergenze all’interno e all’esterno dell’Unione.</div>\n</div>"]]}, "8": {"label": "Articolo 8", "heading": "Azioni di preparazione generali della Commissione", "anchor": "art_8", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La Commissione svolge le seguenti azioni di preparazione:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gestisce l’ERCC;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gestisce il CECIS per assicurare la comunicazione e lo scambio di informazioni tra l’ERCC e i punti di contatto degli Stati membri;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">collabora con gli Stati membri:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per mettere a punto sistemi transnazionali di rilevamento e di allerta rapida di interesse per l’Unione al fine di attenuare gli effetti immediati delle catastrofi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per integrare meglio i sistemi transnazionali di rilevamento e di allerta rapida esistenti sulla base di un approccio multirischio, al fine di ridurre i tempi necessari per reagire alle catastrofi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per mantenere e sviluppare ulteriormente la conoscenza situazionale e la capacità di analisi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iv) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per monitorare le catastrofi e, se del caso, l’impatto dei cambiamenti climatici e fornire consulenze sulla base delle relative conoscenze scientifiche;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>v) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per tradurre le informazioni scientifiche in informazioni operative;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>vi) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per istituire, mantenere e sviluppare partenariati scientifici europei nel campo dei rischi di origine naturale o antropica, che a loro volta dovrebbero promuovere la connessione tra i sistemi nazionali di allerta rapida e di allarme e il collegamento di tali sistemi con l’ERCC e il CECIS;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>vii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per coadiuvare, con conoscenze scientifiche, tecnologie innovative e competenze, gli sforzi degli Stati membri e delle organizzazioni internazionali autorizzate quando gli Stati membri e tali organizzazioni potenziano ulteriormente i loro sistemi di allerta rapida, anche attraverso la rete unionale della conoscenza in materia di protezione civile di cui all’articolo 13;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">predispone e gestisce la capacità di mobilitare e inviare squadre di esperti incaricate di:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">valutare le necessità che possono eventualmente essere soddisfatte nell’ambito del meccanismo unionale nello Stato membro o del paese terzo che chiede assistenza;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">facilitare, ove necessario, il coordinamento sul posto dell’assistenza fornita in risposta alle catastrofi e relazionarsi con le autorità competenti dello Stato membro o del paese terzo che chiede assistenza; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">fornire consulenza allo Stato membro o al paese terzo che richiede assistenza sulle azioni di prevenzione, preparazione o risposta;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">predispone e mantiene la capacità di fornire supporto logistico alle squadre di esperti di cui alla lettera d);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sviluppa e mantiene una rete di esperti formati provenienti dagli Stati membri che, con breve preavviso, possano rendersi disponibili per assistere l’ERCC nel monitoraggio delle informazioni e nella facilitazione del coordinamento;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">facilita il coordinamento del preposizionamento da parte degli Stati membri dei mezzi di risposta alle catastrofi all’interno dell’Unione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sostiene gli sforzi intesi a migliorare l’interoperabilità dei moduli e di altri mezzi di risposta, tenendo conto delle migliori prassi a livello degli Stati membri e a livello internazionale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adotta, nei limiti delle sue competenze, le misure necessarie per facilitare il supporto della nazione ospitante, anche tramite l’elaborazione e l’aggiornamento, in cooperazione con gli Stati membri, di linee guida sul supporto della nazione ospitante basati sull’esperienza operativa;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>j) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sostiene l’istituzione di programmi di valutazione volontaria inter pares delle strategie di preparazione degli Stati membri, sulla base di criteri predefiniti che consentano di formulare raccomandazioni per rafforzare il livello di preparazione dell’Unione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>k) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">in stretta consultazione con gli Stati membri, intraprende altre necessarie azioni di preparazione complementari e di supporto al fine di conseguire l’obiettivo di cui all’articolo 3, paragrafo 1, lettera b); e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>l) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sostiene gli Stati membri, su loro richiesta, in caso di catastrofi che si verifichino all’interno del loro territorio fornendo la possibilità di ricorrere a partenariati scientifici europei per analisi scientifiche mirate. Le analisi risultanti possono essere condivise tramite il CECIS, con l’accordo degli Stati membri colpiti.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Su richiesta di uno Stato membro, di un paese terzo o delle Nazioni Unite o loro agenzie, la Commissione può garantire un’attività di consulenza in merito alle misure di preparazione inviando sul posto una squadra di esperti.</div>\n</div>"]]}, "9": {"label": "Articolo 9", "heading": "Azioni generali di preparazione degli Stati membri", "anchor": "art_9", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli Stati membri si adoperano, su base volontaria, per costituire moduli, in particolare al fine di rispondere alle necessità prioritarie di intervento o di supporto nell'ambito del meccanismo unionale.</div>\n</div>"], [null, "<p class=\"norm\">Nell'ambito dei rispettivi servizi competenti e, in particolare, dei servizi di protezione civile o di altri servizi di emergenza, gli Stati membri individuano in anticipo i moduli, altri mezzi di risposta e esperti che potrebbero essere messi a disposizione per interventi su richiesta tramite il meccanismo unionale. Essi tengono conto del fatto che la composizione dei moduli o degli altri mezzi di risposta può dipendere dal tipo di catastrofe e dalle particolari necessità che derivano dalla catastrofe.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">I moduli sono costituiti dalle risorse di uno o più Stati membri e:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sono in grado di svolgere compiti predefiniti nei settori d'intervento conformemente alle linee guida internazionalmente riconosciute e sono pertanto atti a:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">essere inviati in tempi molto brevi in seguito a una richiesta di assistenza inoltrata tramite l'ERCC; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">operare in modo autosufficiente e autonomo per un periodo di tempo determinato;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sono interoperabili con altri moduli;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">svolgono formazioni e esercitazioni per garantire il requisito di interoperabilità;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sono posti sotto l'autorità di una persona responsabile del funzionamento di moduli; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sono in grado di cooperare con altri organi dell'Unione e/o istituzioni internazionali, in particolare le Nazioni Unite, se del caso.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Gli Stati membri individuano in anticipo, su base volontaria, gli esperti che potrebbero essere inviati quali membri delle squadre di esperti di cui all'articolo 8, lettera d).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Gli Stati membri considerano la possibilità di fornire, se necessario, altri mezzi di risposta, che potrebbero essere messi a disposizione dai servizi competenti o che possono essere forniti da organizzazioni non governative e altri organismi competenti.</div>\n</div>"], [null, "<p class=\"norm inline-element\">Altri mezzi di risposta possono includere risorse di uno o più Stati membri e, se del caso, sono in grado di:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">svolgere compiti predefiniti nel settore della risposta conformemente alle linee guida internazionalmente riconosciute e sono pertanto atti a:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">essere inviati in tempi molto brevi in seguito a una richiesta di assistenza inoltrata tramite l'ERCC; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">operare, se necessario, in modo autosufficiente e autonomo per un periodo di tempo determinato;</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">cooperare, a seconda dei casi, con altri organi dell'Unione e/o istituzioni internazionali, in particolare le Nazioni Unite.</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Nel rispetto di adeguati vincoli di sicurezza, gli Stati membri possono fornire informazioni sulle capacità militari pertinenti da utilizzare in ultima istanza nel quadro dell'assistenza prestata tramite il meccanismo unionale, come il supporto sul piano dei trasporti, logistico e medico.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Gli Stati membri comunicano alla Commissione le informazioni utili su esperti, moduli e altri mezzi di risposta che essi mettono a disposizione per l'assistenza tramite il meccanismo unionale a norma dei paragrafi da 1 a 5 e provvedono ad aggiornare queste informazioni se necessario.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Gli Stati membri designano i punti di contatto di cui all'articolo 8, lettera b), e ne informano la Commissione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Gli Stati membri intraprendono le azioni di preparazione appropriate per facilitare il supporto della nazione ospitante.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">Gli Stati membri, con il sostegno della Commissione, a norma dell'articolo 23, adottano le misure appropriate per assicurare il trasporto tempestivo dell'assistenza da essi offerta.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">10.  </span>\n<div class=\"norm inline-element\">Quando i servizi di emergenza sono forniti da Galileo, Copernicus, GOVSATCOM o altre componenti del programma spaziale istituito dal regolamento (UE) 2021/696 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">2</span>\n), ogni Stato membro può decidere di utilizzarli.</div>\n</div>"], [null, "<p class=\"norm\">Qualora uno Stato membro decida di ricorrere ai servizi di emergenza forniti da Galileo di cui al primo comma, esso individua e comunica alla Commissione le autorità nazionali autorizzate a utilizzare i servizi di emergenza in questione.</p>"]]}, "10": {"label": "Articolo 10", "heading": "Elaborazione di scenari e pianificazione della gestione delle catastrofi", "anchor": "art_10", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La Commissione e gli Stati membri collaborano per migliorare la pianificazione intersettoriale della gestione dei rischi di catastrofi a livello di Unione, sia per le catastrofi naturali che per quelle provocate dall’uomo che provocano o sono in grado di provocare effetti transfrontalieri multinazionali, ivi compresi gli impatti negativi dei cambiamenti climatici. La pianificazione comprende l’elaborazione di scenari a livello di Unione per la prevenzione, la preparazione e la risposta alle catastrofi, tenendo conto del lavoro svolto in relazione agli obiettivi dell’Unione in materia di resilienza alle catastrofi di cui all’articolo 6, paragrafo 5, e del lavoro della rete unionale della conoscenza in materia di protezione civile di cui all’articolo 13, sulla base:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">delle valutazioni del rischio di cui all’articolo 6, paragrafo 1, lettera a);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">della panoramica dei rischi di cui all’articolo 5, paragrafo 1, lettera c);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">della valutazione degli Stati membri della capacità di gestione dei rischi di cui all’articolo 6, paragrafo 1, lettera b);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iv) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dei dati disponibili sulle perdite dovute a catastrofi, di cui all’articolo 6, paragrafo 1, lettera f);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>v) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dello scambio volontario delle informazioni esistenti sulle pianificazioni della gestione dei rischi di catastrofe a livello nazionale o al livello subnazionale appropriato;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>vi) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">della mappatura delle attività; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>vii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dell’elaborazione di piani per la mobilitazione dei mezzi di risposta.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Nel pianificare le operazioni di risposta a crisi umanitarie al di fuori dell’Unione, la Commissione e gli Stati membri individuano e favoriscono le sinergie tra l’assistenza di protezione civile e i finanziamenti destinati agli aiuti umanitari erogati dall’Unione e dagli Stati membri.</div>\n</div>"]]}, "11": {"label": "Articolo 11", "heading": "Pool europeo di protezione civile", "anchor": "art_11", "frags": [[null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">È istituito un pool europeo di protezione civile. Esso è costituito da un pool di mezzi di risposta preimpegnati volontariamente degli Stati membri e comprendente moduli, altri mezzi di risposta e categorie di esperti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1 <span class=\"italics\">bis</span>.  </span>\n<div class=\"norm inline-element\">L'assistenza fornita da uno Stato membro tramite il pool europeo di protezione civile è complementare alle risorse esistenti nello Stato membro richiedente, fatta salva la responsabilità primaria degli Stati membri in materia di prevenzione e risposta alle catastrofi sul loro territorio.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Sulla scorta dei rischi individuati, dell’insieme delle risorse e delle carenze e di eventuali elaborazioni esistenti degli scenari di cui all’articolo 10, paragrafo 1, la Commissione definisce, mediante atti di esecuzione, le tipologie e specifica la quantità dei principali mezzi di risposta necessari per il pool europeo di protezione civile («obiettivi di capacità»). Tali atti di esecuzione sono adottati secondo la procedura d’esame di cui all’articolo 33, paragrafo 2.</div>\n</div>"], [null, "<p class=\"norm\">La Commissione, di concerto con gli Stati membri, monitora i progressi verso gli obiettivi di capacità definiti negli atti di esecuzione di cui al primo comma del presente paragrafo e individua le carenze potenzialmente significative in termini di mezzi di risposta nel pool europeo di protezione civile. Ove siano state individuate tali carenze, la Commissione esamina se gli Stati membri dispongono di risorse necessarie al di fuori del pool europeo di protezione civile. La Commissione incoraggia gli Stati membri a rimediare alle carenze significative in termini di mezzi di risposta nel pool europeo di protezione civile. A tal fine può offrire un sostegno agli Stati membri conformemente all’articolo 20, all’articolo 21, paragrafo 1, punto i), e all’articolo 21, paragrafo 2.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La Commissione determina i requisiti di qualità dei mezzi di risposta che gli Stati membri impegnano nell'ambito <span>\n<span class=\"boldface\">►M2</span>\n</span> dell'pool europeo di protezione civile<span class=\"boldface\"> ◄ </span>. I requisiti di qualità si basano su criteri internazionali riconosciuti, laddove tali criteri già esistano. Gli Stati membri sono responsabili della qualità dei rispettivi mezzi di risposta.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La Commissione definisce e gestisce un processo di certificazione e registrazione dei mezzi di risposta che gli Stati membri mettono a disposizione <span>\n<span class=\"boldface\">►M2</span>\n</span> dell'pool europeo di protezione civile<span class=\"boldface\"> ◄ </span>.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Gli Stati membri identificano e registrano, su base volontaria, i mezzi di risposta che impegnano nell'ambito dell'<span>\n<span class=\"boldface\">►M2</span>\n</span> pool europeo di protezione civile<span class=\"boldface\"> ◄ </span>. I moduli multinazionali creati da due o più Stati membri sono registrati congiuntamente da tutti gli Stati membri interessati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">I mezzi di risposta che gli Stati membri mettono a disposizione <span>\n<span class=\"boldface\">►M2</span>\n</span> dell'pool europeo di protezione civile<span class=\"boldface\"> ◄ </span> rimangono sempre a disposizione a fini nazionali.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">I mezzi di risposta che gli Stati membri mettono a disposizione <span>\n<span class=\"boldface\">►M2</span>\n</span> dell'pool europeo di protezione civile<span class=\"boldface\"> ◄ </span> sono a disposizione delle operazioni di risposta nell'ambito del meccanismo unionale previa richiesta di assistenza inoltrata tramite l'ERCC. La decisione finale sulla loro mobilitazione è presa dagli Stati membri che hanno registrato i mezzi di risposta interessati. Qualora emergenze nazionali, cause di forza maggiore o, in casi eccezionali, altri motivi gravi impediscano a uno Stato membro di mettere a disposizione tali mezzi di risposta per una specifica catastrofe, tale Stato membro ne informa quanto prima la Commissione con riferimento al presente articolo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Ove siano mobilitati, i mezzi di risposta degli Stati membri rimangono sotto il loro comando e il loro controllo e possono essere ritirati qualora emergenze nazionali, cause di forza maggiore o, in casi eccezionali, altri motivi gravi impediscano a uno Stato membro di mantenere a disposizione i propri mezzi di risposta, previa consultazione con la Commissione. La Commissione facilita, ove necessario, il coordinamento tra i diversi mezzi di risposta tramite l'ERCC a norma degli articoli 15 e 16.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">Gli Stati membri e la Commissione garantiscono una conoscenza pubblica adeguata agli interventi cui partecipa <span>\n<span class=\"boldface\">►M2</span>\n</span> l'pool europeo di protezione civile<span class=\"boldface\"> ◄ </span>.</div>\n</div>"]]}, "12": {"label": "Articolo 12", "heading": "rescEU", "anchor": "art_12", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">È istituito rescEU per fornire assistenza in situazioni particolarmente pressanti in cui l'insieme delle risorse esistenti a livello nazionale nonché i mezzi preimpegnati dagli Stati membri nel pool europeo di protezione civile non sono in grado, in determinate circostanze, di garantire una risposta efficace ai vari tipi di catastrofi di cui all'articolo 1, paragrafo 2.</div>\n</div>"], [null, "<p class=\"norm\">Al fine di garantire una risposta efficace alle catastrofi, la Commissione e gli Stati membri assicurano, ove opportuno, un'adeguata distribuzione geografica delle risorse di rescEU.</p>"], [null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La Commissione definisce, mediante atti di esecuzione, le risorse di rescEU, in base, inter alia, agli scenari esistenti di cui all’articolo 10, paragrafo 1, tenendo conto dei rischi individuati ed emergenti e dell’insieme delle risorse e delle carenze a livello di Unione, in particolare nel settore della lotta aerea agli incendi boschivi, degli incidenti di tipo chimico, biologico, radiologico e nucleare, della risposta sanitaria d’emergenza nonché dei trasporti e della logistica. Tali atti di esecuzione sono adottati secondo la procedura d’esame di cui all’articolo 33, paragrafo 2. La Commissione aggiorna regolarmente le informazioni sul tipo e sul numero di risorse di rescEU e mette tali informazioni direttamente a disposizione del Parlamento europeo e del Consiglio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Le risorse di rescEU sono acquistate, affittate, noleggiate o altrimenti acquisite dagli Stati membri.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3 <span class=\"italics\">bis</span>.  </span>\n<div class=\"norm inline-element\">Le risorse di rescEU, quali definite mediante atti di esecuzione adottati secondo la procedura d’esame di cui all’articolo 33, paragrafo 2, possono essere affittate, noleggiate o altrimenti acquisite dalla Commissione nella misura necessaria a rimediare alle carenze nel settore dei trasporti e della logistica.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3 <span class=\"italics\">ter</span>.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">In casi di urgenza debitamente giustificati, la Commissione può acquistare, affittare, noleggiare o altrimenti acquisire risorse definite mediante atti di esecuzione adottati secondo la procedura d’urgenza di cui all’articolo 33, paragrafo 3. Tali atti di esecuzione:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">determinano il tipo e la quantità necessari di mezzi materiali e gli eventuali servizi di sostegno già definiti come risorse di rescEU; e/o</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">definiscono i mezzi materiali aggiuntivi e gli eventuali servizi di sostegno come risorse di rescEU e determinano il tipo e la quantità necessari di tali risorse.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3 <span class=\"italics\">quater</span>.  </span>\n<div class=\"norm inline-element\">Le norme finanziarie dell’Unione si applicano in caso di acquisto, affitto, noleggio o acquisizione di altro tipo di risorse di rescEU da parte della Commissione. In caso di acquisto, affitto, noleggio o acquisizione di altro tipo di risorse di rescEU da parte degli Stati membri, la Commissione può concedere agli Stati membri sovvenzioni dirette senza invito a presentare proposte. Per acquisire risorse di rescEU, la Commissione e gli Stati membri che lo desiderino possono avviare una procedura di aggiudicazione congiunta condotta a norma dell’articolo 165 del regolamento (UE, Euratom) 2018/1046 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">3</span>\n) («regolamento finanziario»).</div>\n</div>"], [null, "<p class=\"norm\">Le risorse di rescEU sono ubicate negli Stati membri che acquistano, affittano, noleggiano o acquisiscono altrimenti dette risorse.</p>"], [null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La Commissione definisce, di concerto con gli Stati membri, i requisiti di qualità delle risorse di risposta che fanno parte di rescEU. I requisiti di qualità si basano su criteri internazionali riconosciuti, laddove tali criteri già esistano.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Uno Stato membro che acquista, affitta o noleggia le risorse di rescEU assicura la registrazione di tali risorse nel CECIS, nonché la disponibilità e la possibilità di mobilitare tali risorse per le operazioni del meccanismo unionale.</div>\n</div>"], [null, "<p class=\"norm\">Le risorse di rescEU possono essere impiegate a fini nazionali ai sensi dell'articolo 23, paragrafo 4 <span class=\"italics\">bis</span>, soltanto laddove non utilizzati o necessari per le operazioni di risposta nell'ambito del meccanismo unionale.</p>"], [null, "<p class=\"norm\">Le risorse di rescEU sono impiegate conformemente agli atti di esecuzione adottati ai sensi dell'articolo 32, paragrafo1, lettera g), e ai contratti operativi tra la Commissione e lo Stato membro che possiede, affitta o noleggia i suddetti mezzi; detti contratti specificano ulteriormente i termini e le condizioni di mobilitazione delle risorse di rescEU, compreso il personale coinvolto.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Le risorse di rescEU sono disponibili per le operazioni di risposta nell'ambito del meccanismo unionale in seguito a una richiesta di assistenza inoltrata tramite l'ERCC, conformemente all'articolo 15 o all'articolo 16, paragrafi da 1 a 9 e paragrafi 11, 12 e 13. La decisione relativa alla loro mobilitazione e smobilitazione, nonché ogni altra decisione in caso di richieste contrastanti, è adottata dalla Commissione in stretto coordinamento con lo Stato membro richiedente e con lo Stato membro che possiede, affitta o noleggia i mezzi, conformemente ai contratti operativi definiti al paragrafo 5, terzo comma, del presente articolo.</div>\n</div>"], [null, "<p class=\"norm\">Lo Stato membro nel cui territorio sono mobilitati le risorse di rescEU è responsabile della conduzione delle operazioni di risposta. Nell'evento di mobilitazioni al di fuori dell'Unione, gli Stati membri che ospitano le risorse di rescEU sono tenuti ad assicurare che dette risorse siano pienamente integrati nella risposta generale.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">In caso di mobilitazione, la Commissione concorda con lo Stato membro richiedente, tramite l'ERCC, la mobilitazione operativa delle risorse di rescEU. Lo Stato membro richiedente facilita il coordinamento operativo delle proprie risorse e delle attività di rescEU nel corso delle operazioni.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">La Commissione facilita, ove opportuno, il coordinamento tra i diversi mezzi di risposta tramite l'ERCC a norma degli articoli 15 e 16.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">Gli Stati membri sono informati dello status operativo delle risorse di rescEU tramite il CECIS.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">10.  </span>\n<div class=\"norm inline-element\">Se una catastrofe che si verifica al di fuori dell'Unione rischia di colpire significativamente uno o più Stati membri o i loro cittadini, le risorse di rescEU possono essere mobilitate a norma dei paragrafi da 6 a 9 del presente articolo.</div>\n</div>"], [null, "<p class=\"norm\">Quando le risorse di rescEU sono mobilitati in paesi terzi, in casi specifici, gli Stati membri possono rifiutare di mobilitare il proprio personale conformemente agli atti di esecuzione adottati ai sensi dell'articolo 32, paragrafo 1, lettera g); detti casi specifici sono ulteriormente definiti nei contratti operativi di cui al paragrafo 5, terzo comma, del presente articolo.</p>"]]}, "13": {"label": "Articolo 13", "heading": "Rete unionale della conoscenza in materia di protezione civile", "anchor": "art_13", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La Commissione istituisce una rete unionale della conoscenza in materia di protezione civile («rete») per riunire, trattare e diffondere conoscenze e informazioni pertinenti per il meccanismo unionale, sulla base di un approccio multirischio e coinvolgendo i pertinenti attori della protezione civile e della gestione delle catastrofi, i centri di eccellenza, le università e i ricercatori.</div>\n</div>"], [null, "<p class=\"norm\">La Commissione, tramite la rete, tiene debitamente conto delle competenze disponibili negli Stati membri, a livello dell’Unione, a livello di altre organizzazioni ed entità internazionali, a livello di paesi terzi nonché a livello delle organizzazioni attive sul campo.</p>"], [null, "<p class=\"norm\">La Commissione e gli Stati membri promuovono una partecipazione equilibrata sotto il profilo del genere all’istituzione e al funzionamento della rete.</p>"], [null, "<p class=\"norm\">La Commissione sostiene, attraverso la rete, la coerenza dei processi decisionali e di pianificazione agevolando uno scambio continuo di conoscenze e informazioni che coinvolga tutti i settori di attività nell’ambito del meccanismo unionale.</p>"], [null, "<p class=\"norm inline-element\">A tal fine la Commissione, attraverso la rete, provvede tra l’altro a:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">mettere a punto e gestire un programma di formazione ed esercitazioni in materia di prevenzione, preparazione e risposta alle catastrofi per il personale della protezione civile e per gli addetti alla gestione delle emergenze. Il programma si concentra, incoraggiandolo, sullo scambio di migliori prassi nel settore della protezione civile e della gestione delle catastrofi, tra cui quelle dovute ai cambiamenti climatici, e comprende corsi comuni e un sistema per lo scambio di competenze nel settore della gestione delle emergenze, compresi scambi di giovani professionisti e volontari con esperienza nonché il distacco di esperti dagli Stati membri.</p>\n</div>\n</div>"], [null, "<p class=\"norm inline-element\">Il programma di formazione ed esercitazioni mira a potenziare il coordinamento, la compatibilità e la complementarità tra le risorse di cui agli articoli 9, 11 e 12, e a migliorare le competenze degli esperti di cui all’articolo 8, paragrafo 1, lettere d) e f);</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">mettere a punto e gestire un programma dedicato alle lezioni apprese da azioni di protezione civile svolte nell’ambito del meccanismo unionale, comprendente aspetti provenienti dall’intero ciclo di gestione delle catastrofi, al fine di fornire un’ampia base per i processi di apprendimento e lo sviluppo delle conoscenze. Il programma include:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il monitoraggio, l’analisi e la valutazione di tutte le azioni di protezione civile pertinenti all’interno del meccanismo unionale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la promozione dell’attuazione delle lezioni apprese al fine di ottenere una base fondata sulle esperienze per lo sviluppo di attività all’interno del ciclo di gestione delle catastrofi; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">lo sviluppo di metodi e di strumenti per la raccolta, l’analisi, la promozione e l’attuazione delle lezioni apprese.</p>\n</div>\n</div>\n<p class=\"list\">Tale programma include inoltre, ove opportuno, le lezioni apprese dagli interventi realizzati al di fuori dell’Unione riguardo allo sfruttamento dei collegamenti e delle sinergie tra l’assistenza fornita nell’ambito del meccanismo unionale e la risposta umanitaria;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">promuovere la ricerca e l’innovazione e incoraggiare l’introduzione e l’impiego di nuove tecnologie o di nuovi approcci pertinenti, o entrambi, ai fini del meccanismo unionale;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">istituire e mantenere una piattaforma online a servizio della rete per sostenere e facilitare l’attuazione dei diversi compiti di cui alle lettere a), b) e c).</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Nello svolgere le attività elencate al paragrafo 1, la Commissione tiene conto, in particolare, delle esigenze e degli interessi degli Stati membri che sono esposti al rischio di catastrofi di natura simile, nonché della necessità di consolidare la protezione della biodiversità e del patrimonio culturale.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La Commissione rafforza la cooperazione in materia di formazione e promuove la condivisione delle conoscenze e delle esperienze tra la rete e le organizzazioni internazionali e i paesi terzi, in particolare al fine di contribuire a rispettare gli impegni internazionali, in particolare quelli del quadro di riferimento di Sendai per la riduzione del rischio di catastrofi 2015-2030.</div>\n</div>"]]}, "14": {"label": "Articolo 14", "heading": "Notifica di una catastrofe all'interno dell'Unione", "anchor": "art_14", "frags": [[null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">In caso di catastrofe in atto o imminente all’interno dell’Unione che provochi o sia in grado di provocare effetti transfrontalieri multinazionali o che colpisca o sia in grado di colpire altri Stati membri, lo Stato membro in cui la catastrofe si verifica o può verificarsi ne dà immediatamente notifica agli Stati membri che rischiano di esserne colpiti e, qualora gli effetti siano potenzialmente significativi, alla Commissione.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<p class=\"norm\">Il primo comma non si applica se l'obbligo di notifica è già stato assolto ai sensi di un'altra normativa dell'Unione, del trattato che istituisce la Comunità europea dell'energia atomica o ai sensi di accordi internazionali esistenti.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">In caso di una catastrofe in atto o imminente all'interno dell'Unione che possa comportare una richiesta di assistenza da parte di uno o più Stati membri, lo Stato membro in cui la catastrofe si verifica o può verificarsi dà immediatamente notifica alla Commissione che è possibile attendersi un'eventuale richiesta di assistenza tramite l'ERCC, in modo che la Commissione possa, se del caso, informare gli altri Stati membri e attivare i servizi competenti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Le notifiche di cui ai paragrafi 1 e 2 sono effettuate, se opportuno, mediante il CECIS.</div>\n</div>"]]}, "15": {"label": "Articolo 15", "heading": "Risposta a catastrofi all'interno dell'Unione", "anchor": "art_15", "frags": [[null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Quando si verifica o è imminente una catastrofe all'interno dell'Unione, lo Stato membro colpito può chiedere assistenza tramite l'ERCC. La richiesta è quanto più specifica possibile. La richiesta di assistenza scade dopo un periodo massimo di 90 giorni, a meno che all'ERCC non vengano comunicati nuovi elementi tali da giustificare la necessità di protrarre o integrare l'assistenza.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">In situazioni eccezionali di maggiore rischio, gli Stati membri possono anche sollecitare assistenza chiedendo il preposizionamento temporaneo dei mezzi di risposta.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Al ricevimento di una richiesta di assistenza, la Commissione ove opportuno e quanto prima:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">inoltra la richiesta ai punti di contatto degli altri Stati membri;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M3\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">raccoglie e analizza informazioni convalidate sulla situazione, in collaborazione con lo Stato membro interessato, al fine di creare una consapevolezza comune della situazione e della risposta alla stessa e di diffondere tali informazioni direttamente agli Stati membri;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">effettua raccomandazioni, previa consultazione dello Stato membro richiedente, per la prestazione di assistenza tramite il meccanismo unionale, in funzione delle necessità sul campo e di eventuali piani prestabiliti rilevanti di cui all'articolo 10, paragrafo 1, invita gli Stati membri a inviare mezzi specifici e facilita il coordinamento dell'assistenza richiesta; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adotta altre misure al fine di facilitare il coordinamento della risposta.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Lo Stato membro che ha ricevuto una richiesta di assistenza tramite il meccanismo unionale decide in tempi rapidi se è in grado di soddisfare la richiesta e informa lo Stato membro richiedente della sua decisione tramite il CECIS, precisando la portata, i termini e, se del caso, i costi dell'assistenza che potrebbe prestare. L'ERCC tiene informati gli Stati membri.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">La direzione degli interventi di assistenza è di competenza dello Stato membro richiedente. Le autorità dello Stato membro richiedente definiscono direttive e delimitano eventualmente i compiti affidati ai moduli o a altri mezzi di risposta. I dettagli dell'esecuzione di questi compiti sono lasciati al responsabile designato dallo Stato membro che presta assistenza. Lo Stato membro richiedente può sollecitare inoltre l'invio di una squadra di esperti che lo coadiuvi nelle operazioni di valutazione, che faciliti il coordinamento sul posto delle squadre inviate dagli Stati membri o che fornisca consulenza tecnica.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Lo Stato membro richiedente adotta le misure appropriate per facilitare il supporto della nazione ospitante all'assistenza che sta per ricevere.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Il ruolo della Commissione di cui al presente articolo non pregiudica le competenze e le responsabilità degli Stati membri riguardo alle loro squadre, moduli e altri tipi di supporto, comprese le capacità militari. In particolare, il supporto della Commissione non implica un comando e controllo delle squadre, dei moduli e di altri tipi di supporto degli Stati membri, che sono mobilitati su base volontaria mediante il coordinamento a livello centrale e sul posto.</div>\n</div>"]]}, "16": {"label": "Articolo 16", "heading": "Promozione della coerenza nella risposta a catastrofi al di fuori dell'Unione", "anchor": "art_16", "frags": [[null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Quando si verifica o è imminente una catastrofe al di fuori dell'Unione, il paese colpito può chiedere assistenza tramite l'ERCC. L'assistenza può altresì essere richiesta tramite le o dalle Nazioni Unite e relative agenzie o altre organizzazioni internazionali rilevanti. La richiesta di assistenza scade dopo un periodo massimo di 90 giorni, a meno che all'ERCC non vengano comunicati nuovi elementi tali da giustificare la necessità di protrarre o integrare l'assistenza.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli interventi ai sensi del presente articolo possono essere condotti sotto forma di interventi di assistenza autonomi o di contributo a un intervento guidato da un'organizzazione internazionale. Il coordinamento dell'Unione è pienamente integrato nel coordinamento generale fornito dall'Ufficio per il coordinamento degli affari umanitari delle Nazioni Unite (OCHA), e ne rispetta il ruolo di guida. In caso di catastrofi provocate dall'uomo o di emergenze complesse, la Commissione garantisce la coerenza con il consenso europeo sull'aiuto umanitario (\n<span class=\"superscript\">4</span>\n) e il rispetto dei principi umanitari.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La Commissione provvede a garantire che l'assistenza sia fornita in modo coerente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">mantenendo un dialogo con i punti di contatto degli Stati membri al fine di assicurare un contributo efficace e coerente all'insieme delle operazioni di soccorso da parte della risposta dell'Unione alle catastrofi attraverso il meccanismo unionale, in particolare:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">informando senza indugio gli Stati membri circa l'insieme delle richieste di assistenza;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">prestando sostegno a una valutazione comune della situazione e delle necessità, dispensando consulenza tecnica e/o facilitando il coordinamento in loco dell'assistenza con squadre di esperti della protezione civile inviate sul posto;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">condividendo con tutti gli attori interessati le pertinenti valutazioni e analisi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iv) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">fornendo una panoramica dell'assistenza offerta dagli Stati membri e da altri attori;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>v) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">fornendo consulenza sul tipo di interventi necessari per garantire che l'assistenza fornita risponda alle necessità individuate;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>vi) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">aiutando a superare eventuali difficoltà pratiche nella distribuzione dell'assistenza sotto l'aspetto a esempio del transito e delle dogane;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">effettuando immediatamente raccomandazioni, se possibile in cooperazione con il paese colpito, in funzione delle necessità sul campo ed eventuali piani prestabiliti pertinenti, invitando gli Stati membri a inviare mezzi specifici e facilitando il coordinamento dell'assistenza richiesta;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">mantenendo i contatti con il paese colpito su dettagli tecnici quali le specifiche necessità di assistenza, l'accettazione di offerte e le modalità pratiche per il ricevimento e la distribuzione dell'assistenza a livello locale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">mantenendo i contatti con l'OCHA o sostenendolo e collaborando con gli altri attori interessati che contribuiscono alle operazioni di soccorso generali, al fine di ottimizzare le sinergie, individuare le complementarità ed evitare duplicazioni e carenze;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">mantenendo i contatti con tutti gli attori interessati, in particolare nella fase finale dell'intervento di assistenza nell'ambito del meccanismo unionale, onde facilitare un ordinato passaggio delle consegne.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Fatto salvo il ruolo della Commissione definito al paragrafo 3, e ferma restando la necessità imperativa di una risposta operativa immediata tramite il meccanismo unionale, la Commissione ad avvenuta attivazione dello stesso informa il Servizio europeo per l'azione esterna onde garantire coerenza tra le operazioni di protezione civile e l'insieme delle relazioni tra l'Unione e il paese colpito. La Commissione tiene gli Stati membri costantemente informati conformemente al paragrafo 3.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Sul posto è opportunamente garantito il collegamento con la delegazione dell'Unione affinché questa possa facilitare i contatti con il governo del paese colpito. Se necessario, la delegazione dell'Unione presta supporto logistico alle squadre di esperti della protezione civile di cui al paragrafo 3, lettera a), punto ii).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Lo Stato membro che ha ricevuto una richiesta di assistenza tramite il meccanismo unionale decide in tempi rapidi se è in grado di soddisfare la richiesta e informa della sua decisione l'ERCC tramite il CECIS, precisando la portata e i termini dell'assistenza che potrebbe prestare. L'ERCC tiene informati gli Stati membri.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Si può altresì ricorrere al meccanismo unionale per fornire sostegno di protezione civile all'assistenza consolare ai cittadini dell'Unione che si trovano in paesi terzi colpiti da catastrofi se richiesto dalle autorità consolari degli Stati membri interessati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Conformemente a una richiesta di assistenza, la Commissione può intraprendere altre necessarie azioni complementari e di supporto per garantire la coerenza nell'invio dell'assistenza.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">Il coordinamento tramite il meccanismo unionale non incide né sui contatti bilaterali tra gli Stati membri e il paese colpito né sulla cooperazione tra gli Stati membri e le Nazioni Unite e altre rilevanti organizzazioni internazionali. Tali contatti bilaterali possono essere anche utilizzati per contribuire al coordinamento mediante il meccanismo unionale.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">10.  </span>\n<div class=\"norm inline-element\">Il ruolo della Commissione di cui al presente articolo non pregiudica le competenze e le responsabilità degli Stati membri riguardo alle loro squadre, moduli e altri tipi di supporto, comprese le capacità militari. In particolare, il supporto della Commissione non implica un comando e controllo delle squadre, dei moduli e di altri tipi di supporto degli Stati membri, che sono mobilitati su base volontaria mediante il coordinamento a livello centrale e sul posto.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">11.  </span>\n<div class=\"norm inline-element\">Sono perseguite sinergie con altri strumenti dell'Unione, in particolare con le azioni finanziate a norma del regolamento (CE) n. 1257/96. La Commissione assicura il coordinamento tra gli strumenti e, ove opportuno, assicura che le azioni di protezione civile degli Stati membri che concorrono a una più ampia risposta umanitaria siano per quanto possibile finanziate a norma della presente decisione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">12.  </span>\n<div class=\"norm inline-element\">Ogniqualvolta sia attivato il meccanismo unionale, gli Stati membri che forniscono l'assistenza in caso di catastrofi tengono l'ERCC costantemente informato sulle attività da essi svolte.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">13.  </span>\n<div class=\"norm inline-element\">Le squadre e i moduli degli Stati membri che partecipano sul posto all'intervento tramite il meccanismo unionale rimangono in stretto contatto con l'ERCC e con le squadre di esperti sul posto di cui al paragrafo 3, lettera a), punto ii).</div>\n</div>"]]}, "17": {"label": "Articolo 17", "heading": "Supporto sul posto", "anchor": "art_17", "frags": [[null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La Commissione può selezionare, nominare e inviare una squadra di esperti provenienti dagli Stati membri:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">in caso di richiesta di consulenza in materia di prevenzione ai sensi dell’articolo 5, paragrafo 2;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">in caso di richiesta di consulenza in materia di preparazione ai sensi dell’articolo 8, paragrafo 2;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">in caso di catastrofe all’interno dell’Unione di cui all’articolo 15, paragrafo 5;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">in caso di catastrofe al di fuori dell’Unione di cui all’articolo 16, paragrafo 3.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Esperti della Commissione e di altri servizi dell’Unione possono essere inseriti nella squadra per coadiuvarla e facilitarne i contatti con l’ERCC. Esperti inviati da agenzie ONU o da altre organizzazioni internazionali possono essere inseriti nella squadra per rafforzare la cooperazione e facilitare le valutazioni comuni.</p>"], [null, "<p class=\"norm\">Laddove l’efficacia operativa lo richieda, la Commissione, in stretta cooperazione con gli Stati membri, può contribuire al coinvolgimento di ulteriori esperti, attraverso la loro mobilitazione, e a un sostegno tecnico e scientifico, e ricorrere a competenze scientifiche, di medicina d’urgenza e settoriali specialistiche.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Gli esperti sono selezionati e nominati secondo la seguente procedura:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli Stati membri designano, sotto la propria responsabilità, gli esperti da mobilitare quali membri per le squadre di esperti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la Commissione seleziona gli esperti e il caposquadra sulla base di qualifiche e esperienze, tra cui il livello di formazione conseguito nell’ambito del meccanismo unionale, esperienze precedenti in missioni svoltesi nell’ambito del meccanismo unionale e altre operazioni di soccorso internazionali; la selezione si basa anche su altri criteri, tra cui la conoscenza delle lingue, in modo da assicurare che la squadra nel suo insieme possieda le competenze adeguate alla situazione specifica;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la Commissione nomina gli esperti e i capisquadra per la missione, d’intesa con gli Stati membri che hanno proceduto alla loro designazione.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">La Commissione comunica agli Stati membri il sostegno supplementare di esperti fornito a norma del paragrafo 1.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Le squadre di esperti inviate facilitano il coordinamento fra le squadre di intervento degli Stati membri e provvedono a relazionarsi con le autorità competenti dello Stato richiedente come previsto all'articolo 8, lettera d). L'ERCC resta in stretto contatto con le squadre di esperti e fornisce loro guida e supporto logistico.</div>\n</div>"]]}, "18": {"label": "Articolo 18", "heading": "Trasporto e attrezzature", "anchor": "art_18", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">In caso di catastrofe all’interno o al di fuori dell’Unione la Commissione può aiutare gli Stati membri ad avere accesso alle attrezzature o alle risorse di trasporto e logistiche:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">fornendo e scambiando informazioni sulle attrezzature e sulle risorse di trasporto e logistiche che gli Stati membri possono mettere a disposizione, al fine di facilitare la messa in comune di tali risorse;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sviluppando materiale cartografico per una diffusione e una mobilitazione rapide delle risorse, tenendo specialmente conto delle peculiarità delle regioni transfrontaliere ai fini dei rischi transfrontalieri multinazionali;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">assistendo gli Stati membri a individuare le risorse di trasporto e logistiche che possono essere messe a disposizione da altre fonti, compreso il mercato commerciale, e facilitandone l’accesso a tali risorse; o</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">assistendo gli Stati membri nell’individuazione delle attrezzature che possono essere messe a disposizione da altre fonti, compreso il mercato commerciale.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La Commissione può integrare le risorse di trasporto e logistiche fornite dagli Stati membri mettendo a disposizione ulteriori risorse necessarie per garantire una risposta rapida alle catastrofi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">L’assistenza richiesta da uno Stato membro o da un paese terzo può consistere esclusivamente in risorse di trasporto e logistiche per rispondere a catastrofi con mezzi di soccorso o attrezzature acquisite in un paese terzo dallo Stato membro o paese terzo richiedente.</div>\n</div>"]]}, "19": {"label": "Articolo 19", "heading": "Risorse di bilancio", "anchor": "art_19", "frags": [[null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La dotazione finanziaria per l'attuazione del meccanismo unionale nel periodo 2014-2020 è fissata a 574 028 000  EUR a prezzi correnti.</div>\n</div>"], [null, "<p class=\"norm\">425 172 000  EUR a prezzi correnti sono attinti dalla rubrica 3 «Sicurezza e cittadinanza» del quadro finanziario pluriennale e 148 856 000  EUR a prezzi correnti dalla rubrica 4 «Ruolo mondiale dell'Europa».</p>"], [null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1 <span class=\"italics\">bis</span>.  </span>\n<div class=\"norm inline-element\">La dotazione finanziaria per l’attuazione del meccanismo unionale nel periodo compreso tra il 1<span class=\"superscript\">o</span> gennaio 2021 e il 31 dicembre 2027 è fissata a 1 263 000 000  EUR a prezzi correnti.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli stanziamenti derivanti da rimborsi da parte dei beneficiari per le azioni di risposta alle catastrofi costituiscono entrate con destinazione specifica ai sensi dell’articolo 21, paragrafo 5, del regolamento finanziario.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">L’assegnazione finanziaria di cui ai paragrafi 1 e 1 <span class=\"italics\">bis</span> del presente articolo e all’articolo 19 <span class=\"italics\">bis</span> può coprire anche le spese di preparazione, monitoraggio, controllo, revisione contabile e valutazione necessarie per gestire il meccanismo unionale e realizzarne gli obiettivi.</div>\n</div>"], [null, "<p class=\"norm\">Queste spese possono coprire in particolare studi, riunioni di esperti, azioni di informazione e comunicazione, tra cui la comunicazione istituzionale delle priorità politiche dell’Unione nella misura in cui si riferiscono agli obiettivi generali del meccanismo unionale, le spese connesse alle reti informatiche destinate all’elaborazione e allo scambio di informazioni e relativa interconnessione con i sistemi attuali e futuri intesi a promuovere lo scambio di dati intersettoriale e relative attrezzature, e tutte le altre spese di assistenza tecnica e amministrativa sostenute dalla Commissione per la gestione del programma.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La dotazione finanziaria di cui al paragrafo 1 <span class=\"italics\">bis</span> del presente articolo e l’importo di cui all’articolo 19 <span class=\"italics\">bis</span>, paragrafo 1, sono assegnati, nel periodo 2021-2027, in base alle percentuali e ai principi di cui all’allegato I.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">La Commissione esamina la ripartizione di cui all’allegato I alla luce dei risultati della valutazione di cui all’articolo 34, paragrafo 3.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Laddove necessario per rispondere alle catastrofi in ragione di imperativi motivi di urgenza o alla luce di eventi imprevisti che incidono sull’esecuzione del bilancio o sull’istituzione delle risorse di rescEU, alla Commissione è conferito il potere di adottare atti delegati conformemente all’articolo 30 al fine di modificare l’allegato I nei limiti degli stanziamenti di bilancio disponibili e secondo la procedura di cui all’articolo 31.</div>\n</div>"]]}, "19a": {"label": "Articolo 19 bis", "heading": "Risorse provenienti dallo strumento dell’Unione europea per la ripresa", "anchor": "art_19a", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Alle misure di cui all’articolo 1, paragrafo 2, lettere d) ed e), del regolamento (UE) 2020/2094 del Consiglio (\n<span class=\"superscript\">5</span>\n) è data attuazione nell’ambito della presente decisione mediante la spesa di un importo fino a un massimo di 2 056 480 000  EUR a prezzi correnti come stabilito all’articolo 2, paragrafo 2, lettera a), punto iii), di tale regolamento a prezzi del 2018, fatto salvo l’articolo 3, paragrafi 3, 4, 7 e 9, dello stesso.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L’importo di cui al paragrafo 1 del presente articolo costituisce entrata con destinazione specifica esterna in conformità dell’articolo 3, paragrafo 1, del regolamento (UE) 2020/2094.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Le misure di cui al paragrafo 1 del presente articolo sono ammissibili per l’assistenza finanziaria alle condizioni stabilite nella presente decisione ed è data loro attuazione nel pieno rispetto degli obiettivi del regolamento (UE) 2020/2094.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Fatte salve le condizioni di ammissibilità delle azioni a favore di paesi terzi stabilite nella presente decisione, l’assistenza finanziaria di cui al presente articolo può essere concessa a un paese terzo solo se essa è attuata nel pieno rispetto degli obiettivi del regolamento (UE) 2020/2094, indipendentemente dal fatto che detto paese terzo partecipi o meno al meccanismo unionale.</div>\n</div>"]]}, "20": {"label": "Articolo 20", "heading": "Azioni generali ammissibili", "anchor": "art_20", "frags": [[null, "<p class=\"norm\">Sono ammesse a beneficiare dell'assistenza finanziaria le seguenti azioni generali volte a potenziare la prevenzione, la preparazione e l'efficacia della risposta alle catastrofi:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">studi, indagini, modelli e sviluppo di scenari intesi a facilitare la condivisione di conoscenze, migliori prassi e informazioni;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">formazione, esercitazioni, workshop, scambio di personale ed esperti, creazione di reti, progetti di dimostrazione e trasferimento di tecnologie;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">attività di monitoraggio, stima e valutazione;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">informazione, educazione e sensibilizzazione dell'opinione pubblica e connesse attività di divulgazione intese a coinvolgere i cittadini nella prevenzione e nella riduzione al minimo degli effetti delle catastrofi nell'Unione e mettere i cittadini dell'Unione in condizione di tutelarsi più efficacemente e in maniera sostenibile;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">elaborazione e svolgimento di un programma dedicato alle lezioni apprese da interventi ed esercitazioni nell'ambito del meccanismo unionale, anche in settori rilevanti per la prevenzione e la preparazione; e</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">attività e misure di comunicazione volte ad accrescere la consapevolezza dell'operato della protezione civile degli Stati membri e dell'Unione in materia di prevenzione, preparazione e risposta alle catastrofi.</p>\n</div>\n</div>"]]}, "20a": {"label": "Articolo 20 bis", "heading": "Visibilità e riconoscimenti", "anchor": "art_20a", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">I destinatari dei finanziamenti dell’Unione e i beneficiari dell’assistenza fornita rendono nota l’origine degli stessi e ne garantiscono la visibilità, in particolare quando promuovono azioni e risultati, fornendo informazioni mirate, coerenti, efficaci e proporzionate a destinatari diversi, compresi i media e il pubblico.</div>\n</div>"], [null, "<p class=\"norm inline-element\">Ai finanziamenti o all’assistenza forniti nel quadro della presente decisione è data adeguata visibilità in linea con gli appositi orientamenti formulati dalla Commissione per gli interventi specifici. In particolare, gli Stati membri assicurano che la comunicazione pubblica concernente le operazioni finanziate nell’ambito del meccanismo unionale:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">includa adeguati riferimenti al meccanismo unionale;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">fornisca un’identità visiva alle risorse finanziate o co-finanziate dal meccanismo unionale;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">diffonda le azioni con l’emblema dell’Unione;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">comunichi in modo proattivo i dettagli del sostegno dell’Unione ai media nazionali e ai portatori di interessi, anche attraverso i loro canali di comunicazione; e</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sostenga le azioni di comunicazione della Commissione relative alle operazioni.</p>\n</div>\n</div>"], [null, "<p class=\"norm\">Laddove le risorse di rescEU siano utilizzate a fini nazionali a norma dell’articolo 12, paragrafo 5, gli Stati membri, con gli stessi mezzi di cui al primo comma del presente paragrafo, ne riconoscono l’origine e garantiscono la visibilità del finanziamento dell’Unione impiegato per acquisirle.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La Commissione realizza azioni di informazione e comunicazione sulla presente decisione, sulle azioni svolte ai sensi della presente decisione e sui risultati ottenuti e sostiene gli Stati membri nelle loro azioni di comunicazione. Le risorse finanziarie destinate alla presente decisione contribuiscono anche alla comunicazione istituzionale delle priorità politiche dell’Unione nella misura in cui tali priorità si riferiscono agli obiettivi di cui all’articolo 3, paragrafo 1.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La Commissione conferisce medaglie per riconoscere e onorare gli impegni di lunga data e i contributi straordinari a favore del meccanismo unionale.</div>\n</div>"]]}, "21": {"label": "Articolo 21", "heading": "Azioni di prevenzione e preparazione ammissibili", "anchor": "art_21", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Sono ammesse a beneficiare dell'assistenza finanziaria le seguenti azioni di prevenzione e preparazione volte a:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">cofinanziare progetti, studi, workshop, sondaggi e azioni e attività analoghe di cui all'articolo 5;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">cofinanziare le valutazioni inter pares di cui all'articolo 6, lettera d), e all'articolo 8, lettera j);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">mantenere le funzioni dell'ERCC, conformemente all'articolo 8, lettera a);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">preparare la mobilitazione e l'invio di squadre di esperti di cui all'articolo 8, lettera d), e all'articolo 17 e sviluppare e mantenere una capacità di intervento tramite una rete di esperti formati a tale scopo provenienti dagli Stati membri di cui all'articolo 8, lettera f);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">creare e mantenere il CECIS e gli strumenti che consentono la comunicazione e lo scambio di informazioni tra l'ERCC e i punti di contatto degli Stati membri e di altri partecipanti nell'ambito del meccanismo unionale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">contribuire allo sviluppo di sistemi transnazionalidi rilevamento, allerta rapida e allarme di interesse europeo per consentire una risposta rapida nonché promuovere l'interconnessione tra sistemi nazionali di allerta rapida e di allarme e la loro connessione con l'ERCC e il CECIS. Questi sistemi tengono conto di e si basano sulle fonti e sui sistemi di informazione, monitoraggio o rilevamento esistenti e futuri;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M3\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sviluppare la pianificazione della gestione dei rischi di catastrofi di cui all’articolo 10;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">supportare le attività di preparazione di cui all'articolo 13;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sviluppare <span>\n<span class=\"boldface\">►M2</span>\n</span> l'pool europeo di protezione civile<span class=\"boldface\"> ◄ </span> di cui all'articolo 11, conformemente al paragrafo 2 del presente articolo.</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M2\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>j) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">istituire, gestire e mantenere le risorse di rescEU conformemente all'articolo 12;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>k) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">garantire la disponibilità del supporto logistico per le squadre di esperti di cui all'articolo 17, paragrafo 1;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>l) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">facilitare il coordinamento del preposizionamento, da parte degli Stati membri, dei mezzi di risposta alle catastrofi all'interno dell'Unione a norma dell'articolo 8, lettera g); e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>m) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">supportare la prestazione di consulenza su misure di prevenzione e preparazione attraverso l'invio di una squadra di esperti sul posto, su richiesta di uno Stato membro, di un paese terzo, delle Nazione Unite o relative agenzie, di cui all'articolo 5, paragrafo 2, e all'articolo 13, paragrafo 3.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L'ammissibilità a beneficiare dell'assistenza finanziaria per l'azione di cui al paragrafo 1, lettera i), è limitata:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ai costi a livello dell'Unione per l'istituzione e la gestione <span>\n<span class=\"boldface\">►M2</span>\n</span> dell'pool europeo di protezione civile<span class=\"boldface\"> ◄ </span> e i processi associati di cui all'articolo 11;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ai costi relativi a corsi di formazione, esercitazioni e workshop obbligatori necessari alla certificazione dei mezzi di risposta degli Stati membri ai fini <span>\n<span class=\"boldface\">►M2</span>\n</span> dell'pool europeo di protezione civile<span class=\"boldface\"> ◄ </span> (\"costi di certificazione\"). I costi di certificazione possono comprendere costi unitari o importi forfettari determinati per tipo di mezzi e coprire fino al 100 % dei costi ammissibili;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M2\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ai costi necessari alla riparazione o all'adeguamento dei mezzi di risposta allo stato di prontezza e disponibilità che li rende atti a essere impiegati nell'ambito del pool europeo di protezione civile, conformemente ai requisiti di qualità del pool europeo di protezione civile e, ove necessario, alle raccomandazioni formulate nel processo di certificazione («costi di adattamento»). Tali costi possono comprendere i costi collegati all'operabilità, all'interoperabilità dei moduli e di altri mezzi di risposta, all'autonomia, autosufficienza e trasportabilità, i costi di imballaggio e altri costi necessari, a condizione che tali costi siano specificamente collegati alla partecipazione dei mezzi al pool europeo di protezione civile.</p>\n<p class=\"list\">I costi di adattamento possono coprire:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il 75 % dei costi ammissibili in caso di adeguamento, a condizione di non superare il 50 % del costo medio di sviluppo del mezzo; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il 75 % dei costi ammissibili in caso di riparazione.</p>\n</div>\n</div>\n<p class=\"list\">I mezzi di risposta che fruiscono di finanziamenti ai sensi dei punti i) e ii) restano disponibili nell'ambito del pool europeo di protezione civile per un periodo minimo collegato ai finanziamenti ottenuti e compreso fra i tre e i dieci anni a partire dalla loro effettiva disponibilità nell'ambito del pool, a meno che il loro ciclo di vita economica non sia più breve.</p>\n<p class=\"list\">I costi di adattamento possono comprendere costi unitari o somme forfettarie determinati per tipo di mezzo.</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M2 —————</p>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">L’assistenza finanziaria per l’azione di cui al paragrafo 1, lettera j), copre tutti i costi necessari per garantire la disponibilità e la possibilità di mobilitare le risorse di rescEU nell’ambito del meccanismo unionale, conformemente al secondo comma del presente paragrafo. Le categorie dei costi ammissibili necessari per garantire la disponibilità e la possibilità di mobilitare le risorse di rescEU sono definite nell’allegato I <span class=\"italics\">bis</span>.</div>\n</div>"], [null, "<p class=\"norm\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all’articolo 30 per modificare l’allegato I <span class=\"italics\">bis</span> relativamente alle categorie di costi ammissibili.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3 <span class=\"italics\">bis</span>.  </span>\n<div class=\"norm inline-element\">L’assistenza finanziaria di cui al presente articolo può essere attuata mediante programmi di lavoro pluriennali. Per le azioni di durata superiore a un anno, gli impegni di bilancio possono essere frazionati in rate annuali.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M3 —————</p>"], [null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">I costi di cui al paragrafo 3 possono comprendere costi unitari, somme forfettarie o tassi forfettari determinati per categoria o tipo di mezzo, a seconda dei casi.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "22": {"label": "Articolo 22", "heading": "Azioni di risposta ammissibili", "anchor": "art_22", "frags": [[null, "<p class=\"norm\">Sono ammesse a beneficiare dell'assistenza finanziaria le seguenti azioni di risposta:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">invio di squadre di esperti di cui all'articolo 17, paragrafo 1, e supporto logistico e invio di esperti di cui all'articolo 8, lettere d) ed e);</p>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">in caso di catastrofe, sostegno agli Stati membri per l’accesso alle attrezzature e alle risorse di trasporto e logistiche, come previsto all’articolo 23; e</p>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">in seguito a una richiesta di assistenza, adozione di altre necessarie azioni complementari e di supporto al fine di facilitare il coordinamento della risposta nel modo più efficace possibile.</p>\n</div>\n</div>"]]}, "23": {"label": "Articolo 23", "heading": "Azioni ammissibili in relazione ad attrezzature e operazioni", "anchor": "art_23", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Sono ammesse a beneficiare dell’assistenza finanziaria le seguenti azioni al fine di consentire l’accesso ad attrezzature e risorse di trasporto e logistiche nell’ambito del meccanismo unionale:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">fornire e scambiare informazioni sulle attrezzature e sulle risorse di trasporto e logistiche che gli Stati membri decidono di mettere a disposizione, al fine di facilitare la messa in comune di tali risorse;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">assistere gli Stati membri nell’individuazione delle risorse di trasporto e logistiche che possono essere messe a disposizione da altre fonti, compreso il mercato commerciale, facilitandone l’accesso a tali risorse;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">assistere gli Stati membri nell’individuazione delle attrezzature che possono essere messe a disposizione da altre fonti, compreso il mercato commerciale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">finanziare le risorse di trasporto e logistiche necessarie per assicurare una risposta rapida in caso di catastrofe. Queste azioni sono ammissibili al sostegno finanziario solo se soddisfano i seguenti criteri:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una richiesta di assistenza è stata inoltrata nell’ambito del meccanismo unionale conformemente agli articoli 15 e 16;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le risorse di trasporto e logistiche supplementari sono necessarie per garantire l’efficacia della risposta alle catastrofi nell’ambito del meccanismo unionale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’assistenza corrisponde alle esigenze individuate dall’ERCC ed è erogata conformemente alle sue raccomandazioni in termini di specifiche tecniche, qualità, tempistica e modalità di erogazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iv) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’assistenza è stata accettata dal paese richiedente, direttamente o tramite le Nazioni Unite o le loro agenzie, o da un’organizzazione internazionale competente, come previsto dal meccanismo unionale; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>v) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’assistenza integra, per le catastrofi in paesi terzi, l’insieme della risposta umanitaria dell’Unione.</p>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1 <span class=\"italics\">bis</span>.  </span>\n<div class=\"norm inline-element\">L’importo dell’assistenza finanziaria dell’Unione per il trasporto di risorse non pre-impegnate nel pool europeo di protezione civile e mobilitate in caso di catastrofe o nell’imminenza di una catastrofe all’interno o al di fuori dell’Unione e per qualsiasi altro sostegno a favore del trasporto necessario per far fronte ad una catastrofe non supera il 75 % dei costi ammissibili totali.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L’importo dell’assistenza finanziaria dell’Unione per le risorse pre-impegnate nel pool europeo di protezione civile non supera il 75 % dei costi di esercizio delle risorse, compreso il trasporto, in caso di catastrofe o nell’imminenza di una catastrofe all’interno o al di fuori dell’Unione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L’assistenza finanziaria dell’Unione per le risorse di trasporto e logistiche può coprire al massimo il 100 % dei costi ammissibili totali specificati alle lettere da a) a d), laddove necessario al fine di rendere operativamente efficace la messa in comune dell’assistenza degli Stati membri e qualora i costi siano connessi:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">alla locazione a breve termine di capacità di deposito per conservare temporaneamente l’assistenza fornita dagli Stati membri al fine di facilitarne il trasporto coordinato;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">al trasporto dallo Stato membro che offre l’assistenza allo Stato membro che ne facilita il trasporto coordinato;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">al riconfezionamento dell’assistenza fornita dagli Stati membri per sfruttare al massimo le risorse di trasporto disponibili o per soddisfare particolari requisiti operativi; o</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">al trasporto locale, al transito e al deposito dell’assistenza messa in comune al fine di garantire una distribuzione coordinata nel luogo di destinazione finale nel paese richiedente.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4 <span class=\"italics\">bis</span>.  </span>\n<div class=\"norm inline-element\">Quando le risorse di rescEU sono impiegate a fini nazionali in conformità dell’articolo 12, paragrafo 5, tutti i costi, compresi quelli di manutenzione e riparazione, sono coperti dallo Stato membro che impiega dette risorse.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4 <span class=\"italics\">ter</span>.  </span>\n<div class=\"norm inline-element\">In caso di mobilitazione di risorse di rescEU nell’ambito del meccanismo unionale, l’assistenza finanziaria dell’Unione copre il 75 % dei costi operativi.</div>\n</div>"], [null, "<p class=\"norm\">In deroga al primo comma, l’assistenza finanziaria dell’Unione copre il 100 % dei costi operativi delle risorse di rescEU necessari in caso di catastrofi poco probabili dall’impatto molto elevato laddove tali risorse siano mobilitate nell’ambito del meccanismo unionale.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4 <span class=\"italics\">quater.</span>  </span>\n<div class=\"norm inline-element\">Per le mobilitazioni al di fuori dell’Unione, di cui all’articolo 12, paragrafo 10, l’assistenza finanziaria dell’Unione copre il 100 % dei costi operativi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4 <span class=\"italics\">quinquies</span>.  </span>\n<div class=\"norm inline-element\">Laddove l’assistenza finanziaria dell’Unione di cui al presente articolo non copra il 100 % dei costi, l’importo rimanente è a carico del richiedente l’assistenza, salvo diverso accordo con lo Stato membro che offre l’assistenza o con lo Stato membro che ospita le risorse di rescEU.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4 <span class=\"italics\">sexies.</span>  </span>\n<div class=\"norm inline-element\">Per la mobilitazione delle risorse di rescEU, l’assistenza finanziaria dell’Unione può coprire il 100 % di tutti i costi diretti necessari per il trasporto di merci, mezzi e servizi logistici all’interno dell’Unione e verso l’Unione in provenienza dai paesi terzi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Nel caso di operazioni congiunte di trasporto che vedano coinvolti più Stati membri, un unico Stato membro può proporsi come guida per richiedere il sostegno finanziario dell’Unione per l’intera operazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Quando uno Stato membro chiede alla Commissione di stipulare contratti di servizi di trasporto, essa sollecita il rimborso parziale dei costi applicando i tassi di finanziamento di cui ai paragrafi 1 <span class=\"italics\">bis</span>, 2 e 4.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6 <span class=\"italics\">bis</span>  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Fatti salvi i paragrafi 1 <span class=\"italics\">bis</span> e 2, il sostegno finanziario dell’Unione per il trasporto dell’assistenza necessario nelle catastrofi ambientali cui si applica il principio «chi inquina paga» può coprire al massimo il 100 % dei costi ammissibili totali. Si applicano le seguenti condizioni:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il sostegno finanziario dell’Unione per il trasporto dell’assistenza è richiesto dallo Stato membro colpito o che presta assistenza sulla base di una valutazione delle esigenze debitamente motivata;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">lo Stato membro colpito o che presta assistenza adotta, se del caso, tutte le misure necessarie per chiedere e ottenere un risarcimento dai responsabili dell’inquinamento, conformemente a tutte le disposizioni giuridiche internazionali, dell’Unione o nazionali applicabili;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">non appena ricevuto il risarcimento dal responsabile dell’inquinamento, lo Stato membro colpito o che presta assistenza rimborsa, se del caso, immediatamente l’Unione.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">In caso di catastrofe ambientale di cui al primo comma che non interessa uno Stato membro, le azioni di cui alle lettere a), b) e c) sono attuate dallo Stato membro che presta assistenza.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">I seguenti costi sono ammissibili all’assistenza finanziaria dell’Unione per le risorse di trasporto e logistiche a norma del presente articolo: tutti i costi connessi allo spostamento di risorse di trasporto e logistiche, compresi i costi di tutti i servizi e i compensi, i costi di logistica e movimentazione, i costi del carburante e dell’eventuale alloggio nonché altri costi indiretti come imposte, compensi in generale e costi di transito.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">I costi di trasporto possono comprendere costi unitari, somme forfettarie o tassi forfettari determinati per categoria di costo.</div>\n</div>"]]}, "24": {"label": "Articolo 24", "heading": "Beneficiari", "anchor": "art_24", "frags": [[null, "<p class=\"norm\">Le sovvenzioni di cui alla presente decisione possono essere concesse a persone giuridiche, di diritto pubblico o privato.</p>"]]}, "25": {"label": "Articolo 25", "heading": "Tipologie di intervento finanziario e modalità di attuazione", "anchor": "art_25", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La Commissione attua il sostegno finanziario dell’Unione conformemente al regolamento finanziario.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La Commissione attua il sostegno finanziario dell’Unione in regime di gestione diretta conformemente al regolamento finanziario o, laddove giustificato dalla natura e dal contenuto dell’azione interessata, in regime di gestione indiretta con gli organismi di cui all’articolo 62, paragrafo 1, lettera c), punti ii), iv), v) e vi), del regolamento finanziario.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il sostegno finanziario ai sensi della presente decisione può assumere le forme previste dal regolamento finanziario, in particolare sovvenzioni, appalti o contributi a fondi fiduciari.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">In conformità dell’articolo 193, paragrafo 2, secondo comma, lettera a), del regolamento finanziario, tenuto conto del ritardo nell’entrata in vigore del regolamento (UE) 2021/836 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">6</span>\n) e al fine di garantire la continuità, nei casi debitamente giustificati specificati nella decisione di finanziamento e per un periodo di tempo limitato, i costi sostenuti in relazione ad azioni sovvenzionate nell’ambito della presente decisione possono essere considerati ammissibili a decorrere dal 1<span class=\"superscript\">o</span> gennaio 2021, anche se sono stati sostenuti prima della presentazione della domanda di sovvenzione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Ai fini dell’attuazione della presente decisione, la Commissione adotta programmi di lavoro annuali o pluriennali mediante atti di esecuzione. Tali atti di esecuzione sono adottati secondo la procedura d’esame di cui all’articolo 33, paragrafo 2. I programmi di lavoro annuali o pluriennali stabiliscono gli obiettivi perseguiti, i risultati attesi, il metodo di attuazione e il loro importo totale. Essi contengono anche una descrizione delle azioni da finanziare, un’indicazione degli importi stanziati per ciascuna azione e un calendario indicativo di attuazione. Per quanto riguarda l’assistenza finanziaria di cui all’articolo 28, paragrafo 2, i programmi di lavoro annuali o pluriennali descrivono le azioni previste per i paesi ivi indicati.</div>\n</div>"], [null, "<p class=\"norm\">Non sono richiesti programmi di lavoro annuali o pluriennali per le azioni che rientrano nella risposta alle catastrofi di cui al capo IV, che non possono essere previste in anticipo.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">A fini di trasparenza e prevedibilità, l’esecuzione del bilancio e gli stanziamenti preventivati per il futuro sono presentati e discussi annualmente in seno al comitato di cui all’articolo 33. Il Parlamento europeo è tenuto informato.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">In aggiunta all’articolo 12, paragrafo 4, del regolamento finanziario, gli stanziamenti d’impegno e di pagamento che non sono stati utilizzati entro la fine dell’esercizio per il quale sono stati iscritti nel bilancio annuale sono riportati automaticamente e possono essere impegnati e pagati fino al 31 dicembre dell’anno successivo. Gli stanziamenti riportati sono utilizzati unicamente per le azioni di risposta. Gli stanziamenti riportati sono i primi da utilizzare nel corso dell’esercizio finanziario successivo.</div>\n</div>"]]}, "26": {"label": "Articolo 26", "heading": "Complementarità e coerenza dell'azione dell'Unione", "anchor": "art_26", "frags": [[null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le azioni finanziate a norma della presente decisione non ricevono assistenza da altri strumenti finanziari dell'Unione. Ciononostante, a norma dell'articolo 191, paragrafo 1, del regolamento (UE, Euratom) 2018/1046 (\n<span class=\"superscript\">7</span>\n), l'assistenza finanziaria concessa ai sensi degli articoli 21, 22 e 23 della presente decisione non impedisce il finanziamento da parte di altri strumenti dell'Unione, conformemente alle condizioni in essi stabilite.</div>\n</div>"], [null, "<p class=\"norm\">La Commissione assicura che i richiedenti l'assistenza finanziaria a norma della presente decisione, e i beneficiari di tale assistenza, le forniscano informazioni sui finanziamenti ottenuti da altre fonti, tra cui il bilancio generale dell'Unione, e sulle richieste di assistenza finanziaria in corso.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Sono sviluppate sinergie, complementarità e maggiore coordinamento con altri strumenti dell'Unione, come quelli che sostengono la coesione, lo sviluppo rurale, la ricerca, la salute, le politiche in materia di migrazione e sicurezza, nonché il Fondo di solidarietà dell'Unione europea. Nel caso di risposta a crisi umanitarie in paesi terzi, la Commissione garantisce complementarità e coerenza tra le azioni finanziate a norma della presente decisione con quelle finanziate a norma del regolamento (CE) n. 1257/96, e che tali azioni siano attuate in linea con il consenso europeo sull'aiuto umanitario.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Se l'assistenza nell'ambito del meccanismo unionale concorre a una risposta umanitaria da parte dell'Unione, in particolare in situazioni emergenziali complesse, le azioni finanziate a norma della presente decisione sono basate sul fabbisogno individuato e sono coerenti con i principi umanitari nonché con i principi che regolano il ricorso alla protezione civile e l'utilizzo delle risorse militari illustrati dal consenso europeo sull'aiuto umanitario.</div>\n</div>"]]}, "27": {"label": "Articolo 27", "heading": "Tutela degli interessi finanziari dell’Unione", "anchor": "art_27", "frags": [[null, "<p class=\"norm\">Un paese terzo che partecipa al meccanismo unionale mediante una decisione adottata a norma di un accordo internazionale o in base a qualsiasi altro strumento giuridico concede i diritti necessari e l’accesso di cui hanno bisogno l’ordinatore responsabile, l’OLAF e la Corte dei conti per esercitare integralmente le rispettive competenze. Nel caso dell’OLAF, tali diritti comprendono il diritto di effettuare indagini, anche attraverso controlli e verifiche sul posto, in conformità del regolamento (UE, Euratom) n. 883/2013 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">8</span>\n).</p>"]]}, "28": {"label": "Articolo 28", "heading": "Paesi terzi e organizzazioni internazionali", "anchor": "art_28", "frags": [[null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il meccanismo unionale è aperto alla partecipazione:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dei paesi dell'Associazione europea di libero scambio (EFTA) membri dello Spazio economico europeo (SEE), nel rispetto delle condizioni di cui all'accordo SEE, e di altri paesi europei se previsto da accordi e procedure;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dei paesi aderenti, dei paesi candidati e candidati potenziali conformemente ai principi, alle modalità e alle condizioni generali che regolano la partecipazione di questi paesi ai programmi dell'Unione stabiliti nei rispettivi accordi quadro e nelle pertinenti decisioni dei consigli di associazione, o in accordi simili.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1 <span class=\"italics\">bis</span>.  </span>\n<div class=\"norm inline-element\">La partecipazione al meccanismo unionale comprende la partecipazione alle sue attività conformemente agli obiettivi, ai requisiti, ai criteri, alle procedure e alle scadenze definiti nella presente decisione ed è conforme alle specifiche condizioni stabilite negli accordi tra l'Unione e lo Stato partecipante.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Possono beneficiare dell'assistenza finanziaria di cui all'articolo 20 e all'articolo 21, paragrafo 1, lettere a), b), f) e h) anche i paesi candidati e i candidati potenziali che non partecipano al meccanismo unionale, nonché i paesi che sono parte della PEV, nella misura in cui tale assistenza finanziaria è complementare ai finanziamenti disponibili conformemente a un futuro atto legislativo dell'Unione relativo all'istituzione dello strumento di assistenza preadesione (IPA II) e conformemente a un futuro atto legislativo dell'Unione relativo all'istituzione di uno strumento europeo di vicinato.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Le organizzazioni internazionali o regionali o i paesi che partecipano alla politica europea di vicinato possono cooperare alle attività nell'ambito del meccanismo unionale se previsto dai pertinenti accordi bilaterali o multilaterali sottoscritti fra dette organizzazioni o detti paesi e l'Unione.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "29": {"label": "Articolo 29", "heading": "Autorità competenti", "anchor": "art_29", "frags": [[null, "<p class=\"norm\">Ai fini dell'applicazione della presente decisione, gli Stati membri designano le autorità competenti e ne danno comunicazione alla Commissione.</p>"]]}, "30": {"label": "Articolo 30", "heading": "Esercizio della delega", "anchor": "art_30", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il potere di adottare atti delegati è conferito alla Commissione alle condizioni stabilite nel presente articolo.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il potere di adottare atti delegati di cui all’articolo 19, paragrafo 6, e all’articolo 21, paragrafo 3, secondo comma, è conferito alla Commissione fino al 31 dicembre 2027.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M3 —————</p>"], [null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La delega di potere di cui all’articolo 19, paragrafo 6, e all’articolo 21, paragrafo 3, secondo comma, può essere revocata in ogni momento dal Parlamento europeo o dal Consiglio. La decisione di revoca pone fine alla delega di potere ivi specificata. Gli effetti della decisione decorrono dal giorno successivo alla pubblicazione della decisione nella <span class=\"italics\">Gazzetta ufficiale dell’Unione europea</span> o da una data successiva ivi specificata. Essa non pregiudica la validità degli atti delegati già in vigore.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Prima dell'adozione dell'atto delegato la Commissione consulta gli esperti designati da ciascuno Stato membro nel rispetto dei principi stabiliti nell'accordo interistituzionale «Legiferare meglio» del 13 aprile 2016.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Non appena adotta un atto delegato, la Commissione ne dà contestualmente notifica al Parlamento europeo e al Consiglio.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">L’atto delegato adottato ai sensi dell’articolo 19, paragrafo 6, o dell’articolo 21, paragrafo 3, secondo comma, entra in vigore solo se né il Parlamento europeo né il Consiglio hanno sollevato obiezioni entro il termine di due mesi dalla data in cui esso è stato loro notificato o se, prima della scadenza di tale termine, sia il Parlamento europeo che il Consiglio hanno informato la Commissione che non intendono sollevare obiezioni. Tale termine è prorogato di due mesi su iniziativa del Parlamento europeo o del Consiglio.</div>\n</div>"]]}, "31": {"label": "Articolo 31", "heading": "Procedura d'urgenza", "anchor": "art_31", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli atti delegati adottati ai sensi del presente articolo entrano in vigore immediatamente e si applicano finché non siano sollevate obiezioni conformemente al paragrafo 2. La notifica di un atto delegato al Parlamento europeo e al Consiglio illustra i motivi del ricorso alla procedura d'urgenza.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il Parlamento europeo o il Consiglio possono sollevare obiezioni a un atto delegato secondo la procedura di cui all'articolo 30, paragrafo 5. In tal caso, la Commissione abroga l'atto immediatamente a seguito della notifica della decisione con la quale il Parlamento europeo o il Consiglio hanno sollevato obiezioni.</div>\n</div>"]]}, "32": {"label": "Articolo 32", "heading": "Atti di esecuzione", "anchor": "art_32", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La Commissione adotta atti di esecuzione sulle seguenti materie:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'interazione dell'ERCC con i punti di contatto degli Stati membri, prevista all'articolo 8, lettera b), all'articolo 15, paragrafo 3, e all'articolo 16, paragrafo 3, lettera a), e le procedure operative per la risposta a catastrofi all'interno dell'Unione, di cui all'articolo 15, e al di fuori dell'Unione, di cui all'articolo 16, tra cui l'identificazione delle organizzazioni internazionali competenti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i componenti del CECIS nonché l'organizzazione dello scambio di informazioni tramite il CECIS di cui all'articolo 8, lettera b);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il processo riguardante l'invio di squadre di esperti di cui all'articolo 17;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'individuazione dei moduli, degli altri mezzi di risposta e degli esperti di cui all'articolo 9, paragrafo 1;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i requisiti operativi per il funzionamento e l'interoperabilità dei moduli di cui all'articolo 9, paragrafo 2, tra cui compiti, mezzi, componenti principali, autosufficienza e mobilitazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli obiettivi del dispositivo, i requisiti di qualità e di interoperabilità e la procedura di certificazione e registrazione necessari al funzionamento <span>\n<span class=\"boldface\">►M2</span>\n</span> dell'pool europeo di protezione civile<span class=\"boldface\"> ◄ </span> di cui all'articolo 11, nonché le disposizioni finanziarie di cui all'articolo 21, paragrafo 2;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M2\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'istituzione, la gestione e il mantenimento di rescEU, di cui all'articolo 12, compresi i criteri per le decisioni di mobilitazione, le procedure operative nonché i costi di cui all'articolo 21, paragrafo 3;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'istituzione e l'organizzazione della rete unionale di conoscenze in materia di protezione civile, di cui all'articolo 13;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h <span class=\"italics\">bis</span>) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le categorie dei rischi poco probabili dall'impatto molto elevato e i rispettivi mezzi per gestirli one di cui all'articolo 21, paragrafo 4;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h <span class=\"italics\">ter</span>) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i criteri e le procedure per riconoscere un impegno di lunga data e i contributi straordinari a favore della protezione civile dell'Unione di cui all'articolo 20, lettera a); e</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M3\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’organizzazione del sostegno per le risorse di trasporto e logistiche di cui agli articoli 18 e 23;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli atti di esecuzione sono adottati secondo la procedura d'esame di cui all'articolo 33, paragrafo 2.</div>\n</div>"]]}, "33": {"label": "Articolo 33", "heading": "Procedura di comitato", "anchor": "art_33", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La Commissione è assistita da un comitato. Esso è un comitato ai sensi del regolamento (UE) n. 182/2011.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Nei casi in cui è fatto riferimento al presente paragrafo, si applica l'articolo 5 del regolamento (UE) n. 182/2011. Quando il comitato non emette parere, la Commissione non adotta il progetto di atto di esecuzione e si applica l'articolo 5, paragrafo 4, terzo comma, del regolamento (UE) n. 182/2011.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Nei casi in cui è fatto riferimento al presente paragrafo, si applica l’articolo 8 del regolamento (UE) n. 182/2011 in combinato disposto con il suo articolo 5.</div>\n</div>"]]}, "34": {"label": "Articolo 34", "heading": "Valutazione", "anchor": "art_34", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le azioni che ricevono assistenza finanziaria sono oggetto di un monitoraggio periodico che ne segue l'attuazione.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Ogni due anni la Commissione presenta al Parlamento europeo e al Consiglio una relazione in merito alle operazioni e ai progressi compiuti nell’ambito dell’articolo 6, paragrafo 5, e degli articoli 11 e 12. Detta relazione contiene informazioni sui progressi compiuti nel conseguimento degli obiettivi dell’Unione in materia di resilienza alle catastrofi e degli obiettivi di capacità, nonché sulle carenze ancora esistenti di cui all’articolo 11, paragrafo 2, tenendo conto della predisposizione delle risorse di rescEU a norma dell’articolo 12. La relazione offre inoltre una panoramica dell’evoluzione del bilancio e dei costi per quanto concerne i mezzi di risposta nonché una valutazione della necessità di sviluppare ulteriormente tali mezzi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Entro il 31 dicembre 2023, e successivamente ogni cinque anni, la Commissione valuta l’applicazione della presente decisione e presenta al Parlamento europeo e al Consiglio una comunicazione sull’efficacia, l’efficienza sotto il profilo dei costi e la prosecuzione dell’attuazione della presente decisione, in particolare per quanto riguarda l’articolo 6, paragrafo 4, le risorse di rescEU e il grado di coordinamento e delle sinergie conseguite con altre politiche, altri programmi e fondi dell’Unione, riguardanti tra l’altro le emergenze mediche. Detta comunicazione è corredata, ove opportuno, di proposte di modifica della presente decisione.</div>\n</div>"]]}, "35": {"label": "Articolo 35", "heading": "Disposizioni transitorie", "anchor": "art_35", "frags": [[null, "<p class=\"norm\">Fino al <span>\n<span class=\"boldface\">►M4</span>\n</span> 31 dicembre 2027<span class=\"boldface\"> ◄ </span>, l'assistenza finanziaria dell'Unione può essere fornita per coprire il 75 % dei costi necessari ad assicurare il rapido accesso alle risorse nazionali corrispondenti a quelli definiti a norma dell'articolo 12, paragrafo 2. A tal fine la Commissione può concedere sovvenzioni dirette agli Stati membri senza invito a presentare proposte.</p>"], [null, "<p class=\"norm\">Le capacità di cui al primo comma sono designati quali risorse di rescEU fino al termine del periodo transitorio.</p>"], [null, "<p class=\"norm\">In deroga all'articolo 12, paragrafo 6, la decisione relativa alla mobilitazione delle risorse di cui al primo comma spetta allo Stato membro che li ha resi disponibili quali risorse di rescEU. Qualora emergenze nazionali, cause di forza maggiore o, in casi eccezionali, altri motivi gravi impediscano a uno Stato membro di mettere a disposizione tali risorse per una specifica catastrofe, tale Stato membro ne informa quanto prima la Commissione con riferimento al presente articolo.</p>"]]}, "36": {"label": "Articolo 36", "heading": "Abrogazione", "anchor": "art_36", "frags": [[null, "<p class=\"norm\">La decisione 2007/162/CE, Euratom e la decisione 2007/779/CE, Euratom sono abrogate. I riferimenti alle decisioni abrogate si intendono fatti alla presente decisione e vanno letti secondo la tavola di concordanza di cui all'allegato II della presente decisione.</p>"]]}, "37": {"label": "Articolo 37", "heading": "Entrata in vigore", "anchor": "art_37", "frags": [[null, "<p class=\"norm\">La presente decisione entra in vigore il giorno successivo alla pubblicazione nella Gazzetta ufficiale dell'Unione europea. Essa si applica a decorrere dal 1<span class=\"superscript\">o</span> gennaio 2014.</p>"]]}}, "recitals": {}};